const response = $('Claude Diagnose').item.json.content[0].text;
const original = $('Error Webhook').item.json;
let diagnosis;
try {
  const cleaned = response.replace(/```json|```/g, '').trim();
  diagnosis = JSON.parse(cleaned);
} catch(e) {
  diagnosis = { title: 'Error: ' + original.error.substring(0, 80), root_cause: response, fix: 'See description', prevention: 'See description', severity: original.severity || 'medium' };
}

return {
  ...diagnosis,
  original_error: original.error,
  original_stack: original.stack,
  app: original.app,
  gh_body: `## Error Report

**App:** ${original.app || 'unknown'}
**Severity:** ${diagnosis.severity}

### Original Error
\`\`\`
${original.error}
\`\`\`

### Stack Trace
\`\`\`
${original.stack || 'not provided'}
\`\`\`

### Root Cause
${diagnosis.root_cause}

### Suggested Fix
${diagnosis.fix}

### Prevention
${diagnosis.prevention}

---
_Auto-generated by n8n error monitor_`
};
